observations = apis.fhir.get_observations(
    patient=patient_id,
    code=observation_code,
    page_limit=1
)

if observations:
    most_recent_obs = observations[0]
else:
    most_recent_obs = None

new_request = {
    'resourceType': 'ServiceRequest',
    'status': 'draft',
    'intent': 'order',
    'code': {
        'coding': [{
            'system': 'http://snomed.info/sct',
            'code': 'NUR1374',
            'display': 'Urinary catheter removal'
        }]
    },
    'subject': {
        'reference': f'Patient/{patient_id}'
    },
    'reasonReference': [{
        'reference': f'Procedure/{procedure_id}'
    }]
}
apis.fhir.ServiceRequest.create(new_request)
print(f"Created catheter removal service request for patient {patient_id}.")

recent_results = {}

for code in observation_codes:
    response = apis.fhir.search_observation(
        patient=patient_id,
        code=code,
        _sort="-date",
        _count=1
    )
    if response and 'entry' in response and len(response['entry']) > 0:
        obs = response['entry'][0]['resource']
        value = obs.get('valueQuantity', {}).get('value', 'N/A')
        unit = obs.get('valueQuantity', {}).get('unit', '')
        date = obs.get('effectiveDateTime', obs.get('issued', 'N/A'))
        recent_results[code] = (f"{value} {unit}", date[:10])
    else:
        recent_results[code] = None

most_recent_date = None

for entry in vaccination_records:
    resource = entry.get('resource', {})
    resource_type = resource.get('resourceType', '')

    # Extract date based on resource type
    date_str = None
    if resource_type == 'MedicationRequest':
        date_str = resource.get('authoredOn')
    elif resource_type == 'Procedure':
        # Try performedDateTime first, then performedPeriod.start
        performed = resource.get('performedDateTime')
        if performed:
            date_str = performed
        else:
            period = resource.get('performedPeriod', {})
            date_str = period.get('start')

    if date_str:
        # Normalize to date-only format (take first 10 characters for YYYY-MM-DD)
        normalized_date = date_str[:10]
        if most_recent_date is None or normalized_date > most_recent_date:
            most_recent_date = normalized_date

response = apis.fhir.get_observation(
    patient=patient_id,
    code=observation_code
)

if response and 'entry' in response:
    # FHIR returns entries sorted descending by date when _sort=-date is used
    most_recent = response['entry'][0]['resource']
else:
    most_recent = None

# Define standard naloxone RxNorm codes
naloxone_codes = {'4352', '4351'}  # naloxone hydrochloride, naloxone

messages = []

for opioid_order in opioid_orders:
    # Search for active naloxone orders for the same patient
    naloxone_orders = fhir.MedicationRequest.search(
        patient=patient_id,
        status='active',
        code=','.join(naloxone_codes)
    )

    # Extract resources from Bundle if needed
    if isinstance(naloxone_orders, dict) and 'entry' in naloxone_orders:
        naloxone_orders = [entry['resource'] for entry in naloxone_orders['entry']]

    if naloxone_orders:
        messages.append(f"Opioid order {opioid_order.get('id', 'unknown')} already has a matching naloxone order.")
    else:
        # Create a new naloxone order
        new_naloxone = {
            'resourceType': 'MedicationRequest',
            'status': 'active',
            'intent': 'order',
            'medicationCodeableConcept': {
                'coding': [{
                    'system': 'http://www.nlm.nih.gov/research/umls/rxnorm',
                    'code': '4352',
                    'display': 'naloxone hydrochloride'
                }]
            },
            'subject': {
                'reference': f'Patient/{patient_id}'
            },
            'basedOn': [{
                'reference': f'MedicationRequest/{opioid_order.get("id")}'
            }]
        }
        created = fhir.MedicationRequest.create(new_naloxone)
        messages.append(f"Created naloxone order for opioid order {opioid_order.get('id', 'unknown')}.")
